def current_lang() -> str:
    return st.session_state.get("lang", DEFAULT_LANG)


def t(key: str, **fmt) -> str:
    """Translate. Falls back: chosen lang → English (global default) →
    Thai (original) → key itself. We prefer English over Thai as the
    fallback because the chosen lang is more likely a non-Thai speaker."""
    entry = STRINGS.get(key, {})
    val = (entry.get(current_lang())
           or entry.get("en")
           or entry.get(DEFAULT_LANG)
           or key)
    if fmt:
        try:
            return val.format(**fmt)
        except (KeyError, IndexError):
            return val
    return val


def is_rtl() -> bool:
    """True if current language is right-to-left (Arabic)."""
    return current_lang() in RTL_LANGS


# ---- Auto-translation cache merge (v45) ---------------------------------
# Translations Claude generated and cached to data/i18n_auto/{lang}.json
# get merged into STRINGS at import time. This makes "Translate UI to X"
# a one-time cost per language — subsequent loads are instant.
try:
    import auto_translate as _auto_translate
    _auto_translate.merge_caches_into_strings()
except Exception:
    # auto_translate is optional — fall back gracefully if module is missing
    pass
